from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""

    # Group triples by subject
    subject_data = {}
    for triple in triples:
        if triple.subject not in subject_data:
            subject_data[triple.subject] = []
        subject_data[triple.subject].append((triple.predicate, triple.object))

    # Get the main subject (likely the astronaut)
    main_subject = triples[0].subject
    data = subject_data.get(main_subject, [])

    # Separate predicates into categories
    personal_info = []
    mission_info = []
    other_info = []

    for pred, obj in data:
        if pred == 'mission':
            mission_info.append(f"mission {obj}")
        elif pred in ['birthDate', 'birthPlace', 'birthName', 'nationality', 'occupation']:
            personal_info.append((pred, obj))
        elif pred in ['timeInSpace', 'dateOfRetirement', 'status', 'awards', 'selectedByNasa']:
            other_info.append((pred, obj))
        else:
            other_info.append((pred, obj))

    # Build sentence parts
    sentence_parts = [f"{main_subject}"]

    # Add occupation if available
    for pred, obj in personal_info:
        if pred == 'occupation':
            sentence_parts.append(f"who worked as a {obj}")
            break

    # Add birth info
    birth_parts = []
    for pred, obj in personal_info:
        if pred == 'birthDate':
            birth_parts.append(f"born on {obj}")
        elif pred == 'birthPlace':
            birth_parts.append(f"from {obj}")
        elif pred == 'birthName':
            birth_parts.append(f"birth name {obj}")
        elif pred == 'nationality':
            birth_parts.append(f"of {obj} nationality")

    if birth_parts:
        sentence_parts.append(f"who was {', '.join(birth_parts)}")

    # Add mission info
    if mission_info:
        mission_str = ', '.join(mission_info)
        sentence_parts.append(f"and participated in {mission_str}")

    # Add other info
    if other_info:
        other_parts = []
        for pred, obj in other_info:
            if pred == 'timeInSpace':
                other_parts.append(f"spent {obj} minutes in space")
            elif pred == 'dateOfRetirement':
                other_parts.append(f"retired in {obj}")
            elif pred == 'status':
                other_parts.append(f"status is {obj}")
            elif pred == 'awards':
                other_parts.append(f"received {obj} awards")
            elif pred == 'selectedByNasa':
                other_parts.append(f"selected by NASA in {obj}")
            else:
                other_parts.append(f"{pred.replace('_', ' ')} {obj}")

        if other_parts:
            sentence_parts.append(f"with {', '.join(other_parts)}")

    # Join all parts
    result = ' '.join(sentence_parts)
    # Clean up double spaces and ensure proper punctuation
    result = ' '.join(result.split())
    if not result.endswith('.'):
        result += '.'

    return result

# EVOLVE-BLOCK-END

